# compute similarity functions
def lcs_len(a, b):
    # dynamic programming LCS length for strings (characters)
    n, m = len(a), len(b)
    # Use simple DP O(n*m) which is small for small strings
    dp = [[0]*(m+1) for _ in range(n+1)]
    for i in range(n-1, -1, -1):
        for j in range(m-1, -1, -1):
            if a[i] == b[j]:
                dp[i][j] = 1 + dp[i+1][j+1]
            else:
                dp[i][j] = max(dp[i+1][j], dp[i][j+1])
    return dp[0][0]

def token_f1(a, b):
    # token-level F1 of overlap
    atoks = a.split()
    btoks = b.split()
    if not atoks or not btoks:
        return 0.0
    a_counts = {}
    for t in atoks:
        a_counts[t] = a_counts.get(t,0) + 1
    b_counts = {}
    for t in btoks:
        b_counts[t] = b_counts.get(t,0) + 1
    overlap = 0
    for t,c in a_counts.items():
        overlap += min(c, b_counts.get(t,0))
    precision = overlap / sum(b_counts.values())
    recall = overlap / sum(a_counts.values())
    if precision+recall==0:
        return 0.0
    return 2*precision*recall/(precision+recall)


